<script setup>

const mapSvg = ref(null)

const isVisible = ref(false);

onMounted(() => {
  const observer = new IntersectionObserver(
    (entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          isVisible.value = true;
          observer.unobserve(entry.target);
        }
      });
    },
    { threshold: 0.1 }
  );

  if (mapSvg.value) {
    observer.observe(mapSvg.value);
  }
});

</script>

<style lang="scss">

@use "sass:math";

.pin-animate_active .Pin-back path {
  animation-name: pin-zoom-out;
  animation-duration: 3s;
  animation-iteration-count: infinite;
  animation-timing-function: ease-in-out;
  transform-origin: center center;
  opacity: 1;
  transform-box: fill-box;
}

// Создаём разные задержки через nth-child
@for $i from 1 through 50 {
  .Pin-back path:nth-child(#{$i}) {
    animation-delay: #{math.random(100)}s;
    animation-duration: #{math.random(3) + 2}s; // от 2 до 5 секунд
    animation-iteration-count: infinite;
    animation-direction: normal;
    animation-timing-function: ease-in-out;
  }
}

// Ключевые кадры
@keyframes pin-zoom-out {
  0% {
    transform: scale(1);
    opacity: 1;
  }
  100% {
    transform: scale(50);
    opacity: 0;
  }
}

.welcome-map {
  font-size: 1rem;
  background-color: #eef1f5;


  
  &__container {
    position: relative;
    max-width: 1920px;
    height: 92em;
    margin-inline: auto;
  }

  &__header {
    position: relative;
    z-index: 2;
    display: flex;
